prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org bbo:name ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") || 
         CONTAINS(LCASE(STR(?normId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") ||
         CONTAINS(LCASE(STR(?modelName)), "01e9c28ede6a4695b91dd90b3e0c5f1b"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName (COUNT(DISTINCT ?msgFlow) as ?msgCount) WHERE {
  ?choreo a bboExt:Choreography .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow .
    ?msgFlow tai:belongsTo ?choreo .
    FILTER(CONTAINS(STR(?task), ?msgFlowSource) || CONTAINS(STR(?task), ?msgFlowTarget))
    OPTIONAL { ?msgFlow bboExt:sourceRef ?msgFlowSource . }
    OPTIONAL { ?msgFlow bboExt:targetRef ?msgFlowTarget . }
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msgFlow) = 2)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
